@Test public void parsesEmptyAttributeKeyWithValue() {
    String html = "<p =value>Test</p>";
    Document doc = Jsoup.parse(html);
    assertEquals("<p>Test</p>", doc.body().html());
}

@Test public void parsesEmptyAttributeKeyWithQuotedValue() {
    String html = "<p =\"quoted\">Test</p>";
    Document doc = Jsoup.parse(html);
    assertEquals("<p>Test</p>", doc.body().html());
}

@Test public void parsesMultipleEmptyAttributeKeys() {
    String html = "<div = =x =>Content</div>";
    Document doc = Jsoup.parse(html);
    assertEquals("<div>Content</div>", doc.body().html());
}
